  /**
   * Perform the control operation given by ``verb`` (``START``, ``STOP``, ``RESTART``, or ``RELOAD``) on the system service named ``service``. This is the general entry point for managing the running state of a service; the configured enable-on-boot setting is changed separately via :doc:`service.update <api_methods_service.update>`.
   *
   * The result reflects whether the service is running after a ``START``, ``RESTART``, or ``RELOAD``, or whether it was successfully stopped for a ``STOP``. By default failures are reported by returning ``false`` rather than raising; set ``options.silent`` to ``false`` to receive an error instead.
   *
   * This method is a job.
   * @roles SERVICE_WRITE, SHARING_FTP_WRITE, SHARING_ISCSI_WRITE, SHARING_NFS_WRITE, SHARING_NVME_TARGET_WRITE, SHARING_SMB_WRITE
   */
  'service.control': {
    params: [verb: Verb2, service: string, options?: ServiceOptions];
    response: boolean;
  };

